def number_to_vietnamese(n):
    if n == 0:
        return 'không'

    ones = ['', 'một', 'hai', 'ba', 'bốn', 'năm', 'sáu', 'bảy', 'tám', 'chín']
    teens = ['mười', 'mười một', 'mười hai', 'mười ba', 'mười bốn', 'mười lăm',
             'mười sáu', 'mười bảy', 'mười tám', 'mười chín']

    if n < 10:
        return ones[n]
    elif n < 20:
        return teens[n - 10]
    elif n < 100:
        tens = n // 10
        unit = n % 10
        result = ones[tens] + ' mươi'
        if unit:
            result += ' ' + ones[unit]
        return result
    # ... mở rộng cho số lớn hơn
    return str(n)

