from functools import wraps

def cache(func):
    _cache = {}

    @wraps(func)
    def wrapper(*args):
        if args in _cache:
            return _cache[args]
        result = func(*args)
        _cache[args] = result
        return result

    wrapper.cache_clear = lambda: _cache.clear()
    return wrapper

